import 'dart:async';
import 'dart:convert';

import '../lib/event_parser.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

bool sameList(List<String> actual, List<String> expected) {
  if (actual.length != expected.length) return false;
  for (var index = 0; index < actual.length; index++) {
    if (actual[index] != expected[index]) return false;
  }
  return true;
}

Future<void> main() async {
  final encoded = utf8.encode('data: ????\r\ndata: fin\r\n');
  final chunks = <List<int>>[];
  for (var index = 0; index < encoded.length;) {
    final width = (index % 3) + 1;
    final end = (index + width < encoded.length) ? index + width : encoded.length;
    chunks.add(encoded.sublist(index, end));
    index = end;
  }
  check(
    sameList(
      await parseEventData(Stream<List<int>>.fromIterable(chunks)).toList(),
      ['????', 'fin'],
    ),
    'international CRLF events survive adversarial byte segmentation',
  );
}
